<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <div class="modal my-popups right fade" data-keyboard="false" data-backdrop="static" id="modalprojectquickviewpop"
            role="dialog" v-cloak>
            <div class="modal-dialog maxwidth500" role="document">
                <div class="modal-content">
                    <div class="modal-header mheader-user">
                        <button type="button" class="close" v-on:click="CloseQuickView()" data-dismiss="modal"><i
                                class="fa fa-times" aria-hidden="true"></i></button>
                        <h4 class="modal-title text-truncate col-8 p-0" id="myModalLabel">{{ $t('Project') }} - {{ ProjectName }}</h4>
                        <span class="user-guide mr-2 float-right">
                            <a class="ancuserguide" data-toggle="collapse" href="#collapseReply" role="button"
                                aria-expanded="false" aria-controls="collapseExample">User Guide</a>
                            <div id="collapseReply" class="divancuserguide collapse" style="top: 58px !important">
                                <div id="scrollbarreplyuserguide" class="custom-scrollbar-js" style="overflow-x: hidden;">
                                    <div class="con">
                                        {{$t("USER_GUIDE_EXP_PROJECT_QUICK_VIEW")}}
                                    </div>
                                </div>
                            </div>
                        </span>
                    </div>
                    <div class="modal-body">
                        <div class="white_bx">
                            <div class="col-lg-12 p-0">
                                <div class="heading-border mb-3" id="status">
                                    <h5 class="h5">
                                        <span>{{$t("Progress")}}</span>
                                        <div class="btnnot px-2 text-white d-block text-center"
                                            v-bind:style="{ backgroundColor: STATUS_BG_COLOR, color: STATUS_COLOR }">
                                            {{ ProjectStatus }} </div>
                                    </h5>
                                </div>
                                <div class="level_info mb-3">
                                    <ul>
                                        <li><b>{{ HoursDone }} </b>{{$t("Done")}}</li>
                                        <li><b>{{ HoursToDo }} </b>{{$t("ToDo")}}</li>
                                    </ul>
                                    <div class="progress prog_bx">
                                        <div class="progress-bar"
                                            v-bind:class="{ 'bg-sky': ExtraHours > 0, 'bg-red': ExtraHours < 0 }"
                                            v-bind:style="{ width: HoursDonePercentage + '%' }" role="progressbar"
                                            aria-valuenow="0" aria-valuemin="0" aria-valuemax="100">
                                        </div>
                                        <div class="progress-bar bg-yellow" v-bind:style="{ width: HoursToDoPercentage + '%' }"
                                            role="progressbar" aria-valuenow="0" aria-valuemin="0" aria-valuemax="100">
                                        </div>
                                    </div>
                                </div>
                                <div class="col-lg-12 p-0">
                                    <div class="heading-border mb-3" id="status">
                                        <h5 class="h5"><span>{{$t("Details")}}</span></h5>
                                    </div>
                                    <ul class="detail_list"> 
                                        <li><b>{{$t('ProjectName')}}</b><span :title="ProjectName || '--'">  {{ TruncateStr(ProjectName, 15) }}</span></li>                                       
                                        <li><b>{{$t('ProjectManager')}}:</b><span :title="PM || '--'">{{ PM ? TruncateStr(PM, 15) : '--' }}</span></li>
                                        
                                        <li><b>{{$t('EventStartDate')}}:</b>
                                            <span>{{ START_DATE ? this.$d(START_DATE) : '--' }}</span>
                                        </li>
                                        <li><b>{{ $t('END_DATE') }}:</b>
                                            <span>{{ END_DATE ? this.$d(END_DATE) : '--' }}</span>
                                        </li>
                                        <li><b>{{$t("EventLocation")}}:</b> <span v-html="LOCATION ? TruncateStr(LOCATION, 20) : '--'"></span></li>
                                        <li><b>{{$t("TotalActiveTask")}}:</b> <span>{{ ACTIVE_TASK }}</span></li>
                                    </ul>

                                    <div class="heading-border mb-3" id="status">
                                        <h5 class="h5"><span>{{$t("Team")}}</span></h5>
                                    </div>
                                    <div id="divscrollsetuptabs" style="max-height:300px;" class="p-0 col-12 float-left w-100">
                                        <div class="customer-headersmall float-left w-100 mb-3" v-for="(item, index) in ProjectTeam" :key="index" v-if="ProjectTeam.length>0">
                                            

                                            <div class="name-circle" style="background: rgb(195 207 213 / 84%);">
                                                <span class="initials user-img-con">
                                                    {{ getFirstTwoInitials(item.Team_Name) }}
                                                </span>
                                            </div>
                                            <div class="conversation-header">
                                                <span>
                                                    <span class="sender-name">{{ item.Team_Name }}</span>                                                    
                                                </span>
                                                
                                            </div>
                                            <div v-if="ProjectTeam.length==0" class="text-center text-danger border p-2 norecord">
                                                {{ $t('NoRecordfound') }}
                                            </div>
                                            </div>
                                        
                                        <div class="text-center text-danger d-flex align-items-center justify-content-center borderbababa p-2 mb-4 no-record"
                                            v-if="ProjectTeam == ''">
                                            {{$t('No_Record_Found')}}
                                        </div>
                                    </div>

                                    <div class="heading-border mb-3 pt-2 float-left w-100" id="status">
                                        <h5 class="h5"><span>{{$t("Files")}}</span></h5>
                                        <div class="text_link">
                                            <a href="javascript:;" v-if="ShowDiv" v-on:click="openUploadFileModel()"><i
                                                    class="fa fa-paperclip pr-2"></i>{{ $t("Add_Files") }} </a>
                                            <a href="javascript:;" v-if="!ShowDiv" v-on:click="BackDetail()"><i
                                                    class="fa fa-angle-double-left pr-2"></i>{{$t("Back")}}</a>
                                        </div>
                                    </div>

                                    <ul class="file-list" v-if="ShowDiv">
                                        <li v-on:click="GetFileDetail('IMAGES')" style="cursor:pointer">
                                            <span class="fldr-icon"><i class="fa fa-folder"></i></span>
                                            <span class="m-text">{{$t("Image")}}</span>
                                            <small>{{ Images }} Items</small>
                                            <a href="javascript:;" class="right-acti d-none"><i
                                                    class="fa fa-ellipsis-h"></i></a>
                                        </li>
                                        <li v-on:click="GetFileDetail('DOCUMENTS')" style="cursor:pointer">
                                            <span class="fldr-icon"><i class="fa fa-folder"></i></span>
                                            <span class="m-text">{{$t("Documents") }}</span>
                                            <small>{{ Documents }} Items</small>
                                            <a href="javascript:;" class="right-acti d-none"><i
                                                    class="fa fa-ellipsis-h"></i></a>
                                        </li>
                                        <li v-on:click="GetFileDetail('VIDEOS')" style="cursor:pointer">
                                            <span class="fldr-icon"><i class="fa fa-folder"></i></span>
                                            <span class="m-text">{{ $t("Videos") }}</span>
                                            <small>{{ Videos }} Items</small>
                                            <a href="javascript:;" class="right-acti d-none"><i
                                                    class="fa fa-ellipsis-h"></i></a>
                                        </li>
                                    </ul>
                                    <div v-if="!ShowDiv">
                                        <div v-if="!noRecordForDetail" v-for="Item in FileDetails" :key="Item.FILE_ID"
                                            id="divscrollsetupfile" class="w-100 d-block"
                                            style="max-height: 200px; overflow-y: auto;">
                                            <a title="flower.jpg" v-on:click="DownloadSingleFile(Item)" href="javascript:;"
                                                class="p-1 m-1 d-block"><span>{{
                                                    Item.LATEST_FILE_NAME }} {{ Item.LATEST_VERSION }}</span></a>
                                        </div>
                                        <div class="text-center text-danger d-flex align-items-center justify-content-center borderbababa p-2 mb-4 no-record"
                                            v-if="noRecordForDetail">
                                            No Record found
                                        </div>
                                    </div>

                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
        <UploadFile v-if="IsFileUploadModalShow" :ProjectId="ProjectId" @GetFilesListing="GetFilesListing"></UploadFile>
    </section>
</template>

<script>
import DataService from '../../services/DataService';
import UploadFile from './UploadFile.vue';

export default {

    components: { UploadFile },

    props: {
        ProjectId: {
            type: String,
            required: true,
        }
    },

    data() {
        return {
            userId: null,
            companyId: null,
            UserType: null,
            PROJECT_NAME: '',
            ProjectStatus: '',
            ACTIVE_TASK: '',
            START_DATE: '',
            END_DATE: '',
            LOCATION: '',
            PM: '',
            Images: '',
            Videos: '',
            Documents: '',
            ProjectTeam: [],
            STATUS_COLOR: '',
            STATUS_BG_COLOR: '',
            secondsPerMinute: 60,
            minutesPerHour: 60,
            HoursDone: 0,
            HoursToDo: 0,
            HoursDonePercentage: 0,
            HoursToDoPercentage: 0,
            ProjectHours: 0,
            ExtraHours: 0,
            PageSize: 10,
            PageNumber: 1,
            ModelSortBy: '',
            ModelSortExp: '',
            noRecordForDetail: false,
            fileData: [],
            ShowDiv: true,
            IsFileUploadModalShow: false,
            FileDetails: [],
            isLoading: false,
            ProjectName:'',

        }
    },
    created: function () {
        debugger
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.companyId = vm.GetUserInfo.CompanyId;
        if (vm.ProjectId != null) {             
            vm.QuickViewByProjectId();           
        }

    },
    methods: {
        GetFilesListing(){            
            this.IsFileUploadModalShow=false;
            this.QuickViewByProjectId();
        },
        QuickViewByProjectId: function () {  
            var ths = this;           
            var url = `projectId=${ths.ProjectId}`;
            DataService.GetProjectQuickViewDetails(url).then((response) => {
                if (response.data.result.project_team.length > 0) {                   
                    ths.ProjectTeam = response.data.result.project_team;
                }
                if (response.data.result.project_detail.length > 0) {
                    debugger
                    ths.ProjectName=response.data.result.project_detail[0].PROJECT_NAME;
                    ths.START_DATE = new Date(response.data.result.project_detail[0].START_DATE);
                    ths.END_DATE = new Date (response.data.result.project_detail[0].END_DATE);
                    ths.LOCATION = response.data.result.project_detail[0].LOCATION;
                    ths.ACTIVE_TASK = response.data.result.project_detail[0].ACTIVE_TASK;
                    ths.PM = response.data.result.project_detail[0].PM;
                    ths.STATUS_BG_COLOR = response.data.result.project_detail[0].STATUS_BG_COLOR;
                    ths.STATUS_COLOR = response.data.result.project_detail[0].STATUS_COLOR;
                    ths.ProjectStatus = response.data.result.project_detail[0].ProjectStatus;
                }
                if (response.data.result.project_files.length > 0) {
                    ths.Images = response.data.result.project_files[0].Images;
                    ths.Videos = response.data.result.project_files[0].Videos;
                    ths.Documents = response.data.result.project_files[0].Documents;
                }
                if(response.data.result.project_hours.length > 0)
                {
                    ths.HoursDone = response.data.result.project_hours.length==0?0: ths.convertSecondsToHHMMSSNew(response.data.result.project_hours[0].TRACK_SECONDS);
                    ths.HoursToDo = response.data.result.project_hours.length==0?0: ths.convertSecondsToHHMMSSNew(response.data.result.project_hours[0].REMAINING_SECONDS);
                    ths.ExtraHours = response.data.result.project_hours.length==0?0:response.data.result.project_hours[0].REMAINING_SECONDS;
                    ths.HoursToDoPercentage = response.data.result.project_hours.length==0?0: response.data.result.project_hours[0].REMAINING_PERCENTAGE;
                    ths.HoursDonePercentage = response.data.result.project_hours.length==0?0: response.data.result.project_hours[0].COMPLETED;
                }
            })
        },

        convertSecondsToHHMMSSNew: function (intSecondsToConvert) {
            var hours = this.convertHours(intSecondsToConvert);
            var minutes = this.getRemainingMinutes(intSecondsToConvert);
            minutes = minutes == 60 ? "00" : minutes;
            var seconds = this.getRemainingSeconds(intSecondsToConvert);
            if (hours < 10 && hours > 0) hours = "0" + hours;
            if (minutes < 10 && minutes > 0) minutes = "0" + minutes;
            if (seconds < 10) seconds = "0" + seconds;
            if (minutes.toString().includes("-")) minutes = minutes.toString().replace("-", "");
            return hours + " h " + minutes + " m "
        },
        convertHours: function (intSeconds) {
            var minutes = this.convertMinutes(intSeconds);
            var hours = Math.floor(minutes / this.minutesPerHour);
            return hours
        },
        convertMinutes: function (intSeconds) {
            return Math.floor(intSeconds / this.secondsPerMinute)
        },
        getRemainingMinutes: function (intSeconds) {
            var intTotalMinutes = this.convertMinutes(intSeconds);
            return intTotalMinutes % this.minutesPerHour
        },
        getRemainingSeconds: function (intTotalSeconds) {
            return intTotalSeconds % this.secondsPerMinute
        },
        CloseQuickView: function () {
            var vm = this;
            vm.$emit('ProjectQuickView ');
        },

        GetFileDetail: function (Type) { 
            var ths = this;
            var url = `projectId=${ths.ProjectId}&pageSize=10&pageNum=1&viewType=${Type}`;
            DataService.GetFileDetails(url).then((response) => {
                if (response.data.result.data.length > 0) {
                    ths.FileDetails = response.data.result.data;
                    ths.noRecordForDetail = false;
                    ths.ShowDiv = false;
                }
                else {
                    ths.noRecordForDetail = true;
                    ths.ShowDiv = false;
                }
            })
        },
        openUploadFileModel: function () {
            var vm = this;
            vm.IsFileUploadModalShow = true;
        },
        BackDetail: function () {
            var vm = this;
            vm.ShowDiv = true;
        },
        // downloadFile(url, filename) {
        //     const response = await fetch(url);
        //     const blob = await response.blob();
        //     const link = document.createElement("a");
        //     link.href = URL.createObjectURL(blob);
        //     link.download = filename;
        //     document.body.appendChild(link);
        //     link.click();
        //     document.body.removeChild(link);
        //     URL.revokeObjectURL(link.href);
        // },
        DownloadSingleFile: function (obj) {
            debugger
            var vm = this;
            vm.isLoading = true;
            var params = `fileId=${obj.FILE_VERSION_ID}&IsVersion=1`;
            DataService.DownloadSingleFile(params).then((response) => {
                debugger
                if (response.data != null) {
                    var fileURL = window.URL.createObjectURL(new Blob([response.data]));
                    var fileLink = document.createElement('a');
                    fileLink.href = fileURL;
                    fileLink.setAttribute('download', obj.LATEST_FILE_NAME);
                    document.body.appendChild(fileLink);
                    fileLink.click();
                    vm.isLoading = false;     
                }
                else {
                    vm.isLoading = false;
                    vm.ShowAlert(vm.$t("FileNotDownload"), "warning", true, vm.$t("Alert"));
                }

            })

        },
        getInitials(name) {
            if (!name) return '';
            return name
                .split(' ')
                .map((n) => n[0])
                .join('')
                .toUpperCase();
        },
        getFirstTwoInitials(fullName) {
            if (!fullName) return "";
            const parts = fullName.trim().split(/\s+/);
            return (parts[0][0] + (parts[1]?.[0] || "")).toUpperCase();
        }      
    }
}
</script>



