<template>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full  d-flex">
                        <h4 class="modal-title">{{ $t('Add') }} {{ $t('Tag') }}</h4>
                        <button type="button" class="close" v-on:click="Close">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>                        
                    </div>
                    <div class="modal-body">
                        <dynamic-form lang="en" :buttons="buttons" :schema="FormSchema" ref="AssignTagForm" :mandatorytext='MandatoryString'
                            v-on:OnSubmit="OnSubmit"></dynamic-form>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>
<script>
import DataService from '../../services/DataService';
export default{
    data(){
        return{
            MandatoryString:'Fields marked with an asterisk (*) are mandatory.',
            FormSchema: [               
                {
                    layoutType: "double",
                    Data: [
                        {
                            astype: "TextField",                                                
                            label: this.$t('Tag Name'),
                            name: "TagName",
                            value: "",                            
                            placeholder: this.$t('Select Tag'),
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "SelectField",                                                
                            label: this.$t('Status'),
                            name: "Tag",
                            value: "1001", 
                            config: {
                                options: [{value:1001,name:'Active'},{value:1002,name:'Inactive'}]
                            },                           
                            placeholder: this.$t('Select Status'),
                            validationRules: { "required": false, max: 100 },
                        } 
                    ]
                },
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "TextAreaField",                 
                            label: this.$t('Description'),
                            name: "Description",
                            value: "",  
                            validationRules: { "required": false, max: 4000 },
                            config: {
                                rows:5
                            }
                        }
                    ]
                }
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                    isVisible:true
                },            
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.Close,
                },
            ],
        }
    },
    created:function(){

    },
    methods:{
        OnSubmit:function(){            
            var ths =this;
            var obj={
                tagId:0,
                tagName:ths.FormSchema[0].Data[0].value,
                tagDesc:ths.FormSchema[1].Data[0].value,
                tagStatusId:ths.FormSchema[0].Data[1].value,
                moduleName:'Project'
            }                        
            var objectPostString = JSON.stringify(obj);              
            DataService.SaveTag(objectPostString).then(function (response) {                
                if(response.data.length>0){
                    if (response.data[0].Status== "Success") {                        
                        ths.ShowAlert(ths.$t('AddedSuccess',[ths.$t('Tag')]), "success", true,  ths.$t("Alert"));                       
                        var param = "id=&moduleName=PROJECT&type=HR_TAG";               
                        DataService.GetDDLData(param).then(function (response1) {                            
                            var json = [];
                            if (response1.data != null) {
                                json = response1.data.DATA;
                            }
                            ths.$emit('updatedata','tag_id', json); 
                            ths.Close();                         
                        });                
                    }
                    else {
                        ths.ShowAlert(ths.$t('UnknownErrorOccur'), "failure", true, ths.$t("Alert"));
                    }
                }
                
            });   
        },
        Close:function(){
            this.$parent.isTag=false;
        }
    }
}
</script>