<template>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full  d-flex">
                        <h4 class="modal-title">{{ $t('Configuration') }}</h4>
                        <button type="button" class="close" v-on:click="Close">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>                        
                    </div>
                    <div class="modal-body">
                        <dynamic-form lang="en" :buttons="buttons" :schema="FormSchema" ref="AssignTagForm"
                            v-on:OnSubmit="onSubmit" :mandatorytext='MandatoryString'></dynamic-form>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>

<script>
import DataService from '../../services/DataService'
export default{
    props:{
        ProjectId:{
            type: Number,
            required: true,
        }
    },
    data(){        
        return{
            isLoading:false,
            MandatoryString:'Fields marked with an asterisk (*) are mandatory.',
            selectedProjectId:0,        
            FormSchema: [],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                    isVisible:true  
                },            
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.Close,
                },
            ],
        }        
    },
    created:function(){        
        var vm=this;        
        vm.companyId = vm.GetUserInfo.CompanyId;
        if(vm.ProjectId != null){
            vm.selectedProjectId=vm.ProjectId;
            vm.ProjectConfiguration();
        }
    },
    methods:{ 
        ProjectConfiguration:function(){            
            var vm=this;
            var url=`projectId=${vm.selectedProjectId}`;
            DataService.ProjectConfiguration(url).then(function (response) {                
                if(response.data.result.length>0){
                    var Moduleid=response.data.result[0].MODULE_ID;
                    vm.GetModuleKeys(Moduleid);
                }
            })
        },       
        Close:function(){
            this.$parent.IsConfiguration=false;
        },
        GetModuleKeys:function(Moduleid){
            var vm =this;
            var url=`moduleId=${Moduleid}&projectuserId=${vm.selectedProjectId}`
            DataService.GetModuleKeys(url).then((response)=>{ 
                if(response.data.result.length>0){               
                    vm.ConvertConfigurationDataIntoDynamicFormobj(response.data.result);
                } 
            });
        },
        ConvertConfigurationDataIntoDynamicFormobj: function(configurations){                
                var ths = this;
                ths.formSchema = [];
                configurations.sort((a,b) => (ths.$t(a.CORE_CONFIG_KEY) > ths.$t(b.CORE_CONFIG_KEY)) ? 1 : ((ths.$t(b.CORE_CONFIG_KEY) > ths.$t(a.CORE_CONFIG_KEY)) ? -1 : 0))
                if(configurations != null && configurations.length > 0){
                    let obj = {
                        layoutType: 'double',
                        groupId: 0,
                        group_name: "",
                        Data: []
                    }                    
                    configurations.forEach(function(item, index){     
                        let validationRules = {}
                        validationRules["required"] = true;
                        let astype = item.ASTYPE
                        let options = []
                        var val = item.CORE_CONFIG_VALUE??""                        
                        if(item.CORE_CONFIG_OPTIONS != null){
                            var optionsArray = item.CORE_CONFIG_OPTIONS.split('^');                            
                            options = optionsArray.map(option => ({
                                value: option,
                                name: ths.$t(option)
                            }));
                        }
                        if(item.SELECT_OPTIONS != null && item.SELECT_OPTIONS != ""){
                            options = ths.MakeNormalArray(item.SELECT_OPTIONS);
                        }
                        let comfigMode = "date";
                        let placeholder = "Enter " + ths.$t(item.CORE_CONFIG_KEY);
                        if(astype == "SelectField" || astype == "CustomSelectField" || astype == "TreeSelectField"){
                            placeholder = "Select " + ths.$t(item.CORE_CONFIG_KEY);
                        }
                        else if(astype == "MultiSelectField"){
                            val = [];
                            let valArray = item.CORE_CONFIG_VALUE.split('^')
                            valArray.forEach(function(x){
                                val.push({
                                    label: x,
                                    value: x
                                })
                            });

                        }else if(astype == "CheckBoxField"){
                            val = item.CORE_CONFIG_VALUE.split('^')
                        }
                        if(astype == "DateField"){
                            comfigMode = "date";
                        }else if (astype == "MultiSelectField"){
                            comfigMode = 'tag'
                        }
                        else if (astype == "FileField"){                            
                            var filePath=item.CORE_CONFIG_VALUE;                           
                            var filename = filePath.split('/').pop();
                        }
                        let fieldObj = {
                            customFieldId: item.CORE_CONFIG_ID,
                            astype: astype,
                            label: ths.$t(item.CORE_CONFIG_KEY),
                            name: item.CORE_CONFIG_KEY,
                            value: val,
                            placeholder: placeholder,
                            mode: comfigMode,
                            config: {
                                maxSize: 100,
                                showSelectedFiles: [{                          
                                    attachmentName: filePath,
                                    attachmentPath: filename
                                }],
                                onChange:ths.onChangeField,
                                onDeleteSelectedFiles:ths.onDeleteSelectedFiles,
                                onClickSelectedFiles:ths.showCompanyLogo,
                                accept: [
                                   { fileType: 'jpg', iconClass: 'fa-file-image-o' },
                                    { fileType: 'jpeg', iconClass: 'fa-file-image-o' },
                                    { fileType: 'png', iconClass: 'fa-file-image-o' },
                                    { fileType: 'pdf', iconClass: 'fa-file-archive-o' },
                                    { fileType: 'mp4', iconClass: 'fa-video-camera' },
                                    { fileType: 'doc', iconClass: 'fa-file-text-o' },
                                    { fileType: 'docx', iconClass: 'fa-file-text-o' },
                                    { fileType: 'xlsx', iconClass: 'fa-file-excel-o' },
                                    { fileType: 'txt', iconClass: 'fa-file-text-o' },
                                    { fileType: 'xls', iconClass: 'fa-file-excel-o' }
                                ],
                                mode: comfigMode,
                                options: options,
                                dependentOn: null,
                                showWhen: null,
                                valueMapping: null,
                                fieldCode: null,
                                showCrossOnSelectedFiles:false,
                            },
                            visibility: true,
                            validationRules: validationRules,
                            dtCode: item.CORE_CONFIG_TYPE
                        }
                        obj.Data.push(fieldObj);
                    })            
                    ths.FormSchema.push(obj);
                }
            },
            onSubmit: function(){   
               // debugger             
                var ths = this;
                ths.isLoading=true;
                var configObj = []
                ths.FormSchema.forEach(function(group, index){
                    group.Data.forEach(function(item, index){
                        var value = item.value;
                        if(item.astype == "CheckBoxField"){
                            value = (item.value.filter((x) => x != "")).join("^");
                        }
                        if(item.astype == 'MultiSelectField'){
                            let val = "";
                            if(typeof(item.value) == 'object'){
                                try{
                                    if(typeof(item.value.length) != 'undefined' && item.value.length > 0 ){
                                        item.value.forEach(function(item){
                                            if(val == ""){
                                                val = item.value;
                                            } else {
                                                val = val + '^' + item.value;
                                            }
                                        })
                                    } else {
                                        val = item.value.value
                                    }
                                }catch(e){
                                    val = item.value.value
                                }
                            } else {
                                val = item.value
                            }
                            value = val;
                        }                       
                        var obj = {
                            DataId: item.customFieldId,
                            key: item.name,
                            DataValue: value
                        }
                        configObj.push(obj)
                    });
                });
                var paramObj = {
                    configData: configObj,
                    conditionData: {
                        refCode: 'ProjectSetting',
                        moduleName: 'PROJECT',
                        ProjectId:ths.ProjectId
                    }
                }                
                var data = JSON.stringify(paramObj);
                //debugger
                DataService.SaveConfigurations(data).then(function (response) {
                    ths.isLoading=false;
                    if(response != null && response.data != null && response.data == 1){
                        ths.ShowAlert(ths.$t('RecordsSavedSuccessfully'), 'success');
                        ths.Close();
                        ths.$parent.FetchData();
                    } else {
                        ths.ShowAlert(ths.$t("UnknownErrorOccur"), "failure", true, ths.$t("Alert"));
                    }
                });
            }
    }
}
</script>